import{_ as e,o,c as a,ae as i}from"./chunks/framework.6gkcVjOI.js";const g=JSON.parse('{"title":"Introduction","description":"What is claude-code-Go? A Go-native implementation of the Claude Code agent architecture","frontmatter":{"title":"Introduction","description":"What is claude-code-Go? A Go-native implementation of the Claude Code agent architecture"},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1775273216000}'),n={name:"guide/introduction.md"};function r(s,t,l,d,c,h){return o(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Welcome to claude-code-Go—a Go implementation of the Claude Code agent system.</p><h2 id="what-is-claude-code-go" tabindex="-1">What is claude-code-Go? <a class="header-anchor" href="#what-is-claude-code-go" aria-label="Permalink to &quot;What is claude-code-Go?&quot;">​</a></h2><p>claude-code-Go is a terminal-based AI coding assistant that implements the complete agent loop with built-in tools, a permission system, MCP (Model Context Protocol) support, and SSE (Server-Sent Events) streaming.</p><p>Core design philosophy: <strong>Model provides intelligence, harness provides reliability.</strong></p><p>The LLM handles understanding intent, deciding tool calls, and interpreting results. The runtime handles permission control, timeout protection, output truncation, and session persistence—ensuring production-grade reliability.</p><p>It operates as:</p><ul><li>An AI assistant that can read, write, and edit files across your project</li><li>An automation tool that executes shell commands for builds, tests, and scripts</li><li>A code navigator that searches your codebase with glob patterns and content search</li><li>An autonomous agent that collaborates with you interactively in a terminal REPL</li></ul><h2 id="how-is-it-different-from-chatbots" tabindex="-1">How is it Different from Chatbots? <a class="header-anchor" href="#how-is-it-different-from-chatbots" aria-label="Permalink to &quot;How is it Different from Chatbots?&quot;">​</a></h2><p>Unlike traditional chatbots that simply respond to messages, claude-code-Go operates as an <strong>autonomous agent</strong> with agency and tool-use capabilities.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Chatbot</th><th>claude-code-Go</th></tr></thead><tbody><tr><td><strong>Interaction Model</strong></td><td>Request-Response</td><td>Continuous agent loop with tool calls</td></tr><tr><td><strong>Capabilities</strong></td><td>Text generation only</td><td>Read, write, edit, execute, search files</td></tr><tr><td><strong>State Management</strong></td><td>Stateless</td><td>Message history + context compaction</td></tr><tr><td><strong>User Control</strong></td><td>Passive recipient</td><td>Active approval for dangerous operations</td></tr><tr><td><strong>Use Case</strong></td><td>Q&amp;A, conversation</td><td>Code development, automation</td></tr></tbody></table><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h2><p>claude-code-Go is built with a minimal, dependency-free philosophy:</p><table tabindex="0"><thead><tr><th>Component</th><th>Technology</th></tr></thead><tbody><tr><td><strong>Language</strong></td><td>Go 1.23+</td></tr><tr><td><strong>Standard Library</strong></td><td>Go stdlib only (no external dependencies in main binary)</td></tr><tr><td><strong>Python Harness</strong></td><td>Optional (for testing, mocking, evaluation)</td></tr><tr><td><strong>API</strong></td><td>Anthropic Messages API with SSE streaming</td></tr></tbody></table><p>The Python harness (<code>harness/</code>) is optional and provides:</p><ul><li>Mock API server for testing without API costs</li><li>Session replay for debugging</li><li>Quality evaluators for integration testing</li></ul><h2 id="core-numbers" tabindex="-1">Core Numbers <a class="header-anchor" href="#core-numbers" aria-label="Permalink to &quot;Core Numbers&quot;">​</a></h2><ul><li><strong>~31</strong> Go source files (non-test)</li><li><strong>~4,000</strong> lines of Go code</li><li><strong>~2,000</strong> lines of Python (harness)</li><li><strong>8</strong> internal modules</li><li><strong>6</strong> built-in tools (Read, Write, Edit, Glob, Grep, Bash)</li></ul><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>This documentation covers the architecture and implementation details of claude-code-Go:</p><ol><li><strong>AI Agent Architecture</strong> — How the agent loop works, decision-making process, and tool selection</li><li><strong>Streaming API Integration</strong> — SSE token streaming from Anthropic&#39;s API with real-time output</li><li><strong>Tool System</strong> — Built-in tools + MCP integration for extending capabilities</li><li><strong>Security Design</strong> — Three-tier permission system for controlling dangerous operations</li><li><strong>Engineering Practice</strong> — Structured logging, graceful shutdown, configuration management</li></ol><h2 id="target-audience" tabindex="-1">Target Audience <a class="header-anchor" href="#target-audience" aria-label="Permalink to &quot;Target Audience&quot;">​</a></h2><p>This documentation is designed for:</p><ul><li><strong>Go developers</strong> interested in building AI-powered tools</li><li><strong>Systems programmers</strong> curious about agent architecture</li><li><strong>DevOps engineers</strong> looking for CLI automation with AI capabilities</li><li><strong>Researchers</strong> exploring LLM application patterns</li></ul><p>You should have familiarity with:</p><ul><li>Go programming language basics</li><li>Terminal/command-line interfaces</li><li>HTTP APIs and JSON data formats</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Ready to get started? Head to the <a href="./quick-start.html">Quick Start</a> guide to run your first command.</p><p>Or dive deeper into the <a href="./../architecture/overview.html">Architecture Overview</a> to understand how the pieces fit together.</p>',29)])])}const p=e(n,[["render",r]]);export{g as __pageData,p as default};
